const Emoji = () => {
  const ref = useRef<RichTextareaHandle>(null);
  const [text, setText] = useState(`Type : to show suggestions 💪\n\n`);
  const [pos, setPos] = useState<{
    top: number;
    left: number;
    caret: number;
  } | null>(null);
  const [index, setIndex] = useState<number>(0);

  const targetText = pos ? text.slice(0, pos.caret) : text;
  const match = pos && targetText.match(MENTION_REG);
  const name = match?.[1] ?? "";
  const filtered = useMemo(
    () => emoji.search(name).slice(0, MAX_LIST_LENGTH),
    [name]
  );
  const complete = (i: number) => {
    if (!ref.current || !pos) return;
    const selected = filtered[i].emoji;
    ref.current.setRangeText(
      `${selected} `,
      pos.caret - name.length - 1,
      pos.caret,
      "end"
    );
    setPos(null);
    setIndex(0);
  };

  return (
    <div>
      <RichTextarea
        ref={ref}
        style={style}
        onChange={(e) => setText(e.target.value)}
        value={text}
        onKeyDown={(e) => {
          if (!pos || !filtered.length) return;
          switch (e.code) {
            case "ArrowUp":
              e.preventDefault();
              const nextIndex = index <= 0 ? filtered.length - 1 : index - 1;
              setIndex(nextIndex);
              break;
            case "ArrowDown":
              e.preventDefault();
              const prevIndex = index >= filtered.length - 1 ? 0 : index + 1;
              setIndex(prevIndex);
              break;
            case "Enter":
              e.preventDefault();
              complete(index);
              break;
            case "Escape":
              e.preventDefault();
              setPos(null);
              setIndex(0);
              break;
            default:
              break;
          }
        }}
        onSelectionChange={(r) => {
          if (
            r.focused &&
            MENTION_REG.test(text.slice(0, r.selectionStart))
          ) {
            setPos({
              top: r.top + r.height,
              left: r.left,
              caret: r.selectionStart,
            });
            setIndex(0);
          } else {
            setPos(null);
            setIndex(0);
          }
        }}
      />
      {pos &&
        createPortal(
          <Menu
            top={pos.top}
            left={pos.left}
            chars={filtered}
            index={index}
            complete={complete}
          />,
          document.body
        )}
    </div>
  );
};

