        <select
          value={granularity}
          onChange={(e) => setGranularity(e.target.value as Granularity)}
        >
          <option value={"grapheme"}>grapheme</option>
          <option value={"word"}>word</option>
          <option value={"sentence"}>sentence</option>
        </select>
